GMG - Roll on Tables.command:
(async () => {
  let options = '';
  game.tables.contents.forEach((t) => {
    if (
      t.folder &&
      (t.folder.name === 'Symbaroum GMG - Tables' ||
        t.folder.name === '01.06 Under, Above & Beyond' ||
        t.folder.name === '01.07 Goal Orientated Roleplaying' ||
        t.folder.name === '02.01 Advanced Traps' ||
        t.folder.name === '02.02 Pitched Battle' ||
        t.folder.name === '02.03 Managing a Domain' ||
        t.folder.name === '02.09 Events' ||
        t.folder.name === '02.10 The Treasures of the Ruins' ||
        t.folder.name === '02.11 Exploring Ruins' ||
        t.folder.name === '02.12 Ceremonies' ||
        t.folder.name === 'Monster Codex') &&
      t.folder.name != null
    ) {
      options = options.concat(`<option value="${t.data._id}">${t.folder.name} - ${t.data.name}</option>`);
    }
  });
  let template = `
                      <form>
                          <div class="form-group">
                              <label>Select Table</label>
                              <select id="tableSelect">${options}</select>
                          </div>
                          <div class="form-group">
                              <label>Rolls on table?</label>
                              <input type="text" id="inputNbr" value=1>
                          </div>
                          <div class="form-group">
                              <label>Modifier?</label>
                              <input type="text" id="inputMod" value="0">
                          </div>
                      </form>`;

  let buttons = {};
  if (game.tables.size > 0) {
    buttons = {
      draw: {
        icon: '<i class="fas fa-check"></i>',
        label: `"Draw`,
        callback: async (html) => {
          const tableId = html.find('#tableSelect')[0].value;
          const table = game.tables.get(tableId);
          const drawNumber = parseInt(html.find('#inputNbr')[0].value || 0);
          const formula = table.data.formula;
          const modifier = parseInt(html.find('#inputMod')[0].value || '0');

          for (let i = 0; i < drawNumber; i++) {
            const roll = new Roll(formula + ' + ' + modifier);
            roll.evaluate({ async: false });
            await table.draw({ roll: roll });
          }
        },
      },
      cancel: {
        icon: '<i class="fas fa-times"></i>',
        label: `Cancel`,
      },
    };
  } else {
    template = `<div style="text-align: center">There are no tables to draw from!</div><br>`;
    buttons = {
      draw: {
        icon: '<i class="fas fa-check"></i>',
        label: 'OK',
      },
    };
  }

  new Dialog(
    {
      title: `Roll on selected table`,
      content: template,
      buttons: buttons,
      default: 'draw',
    },
    {
      width: 530,
    }
  ).render(true);
})();
